class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        vector<bool> visited(nums.size(), false);
        sort(nums.begin(), nums.end(), greater<int>());
        return dfs(nums, target, 0, visited, k);
    }

    bool dfs(vector<int>& nums, int target, int index, vector<bool>& visited, int k) {
        if (k == 1) return true;
        for (int i = index; i < nums.size(); i++) {
            if (visited[i] || nums[i] > target) continue;
            visited[i] = true;
            if (dfs(nums, target, i + 1, visited, k - 1)) return true;
            visited[i] = false;
        }
        return false;
    }
};
